const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

/**
 * Serves a file from Cloud Storage based on query parameters.
 *
 * @param {object} req The HTTP request object.
 * @param {object} res The HTTP response object.
 */
exports.serveFileFromGCS = async (req, res) => {
  const bucketName = req.query.bucket;
  const filePath = req.query.filePath; // This supports nested paths like 'folder/subfolder/file.txt'

  if (!bucketName || !filePath) {
    res.status(400).send('Bad Request: "bucket" and "filePath" query parameters are required.');
    return;
  }

  try {
    const bucket = storage.bucket(bucketName);
    const file = bucket.file(filePath);

    // Check if the file exists
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send(`Not Found: File "${filePath}" not found in bucket "${bucketName}".`);
      return;
    }

    // Attempt to get file metadata to set Content-Type, if available.
    // This makes the streamed file render correctly in browsers.
    try {
      const [metadata] = await file.getMetadata();
      if (metadata && metadata.contentType) {
        res.setHeader('Content-Type', metadata.contentType);
      } else {
        // Fallback to a generic content type if not found
        res.setHeader('Content-Type', 'application/octet-stream');
      }
      // Optionally set Content-Disposition to suggest download filename, or inline for display
      res.setHeader('Content-Disposition', `inline; filename="${file.name.split('/').pop()}"`);

    } catch (metadataErr) {
      console.warn(`Could not fetch metadata for ${filePath} in ${bucketName}:`, metadataErr.message);
      // Proceed without specific Content-Type if metadata fetch fails
      res.setHeader('Content-Type', 'application/octet-stream');
    }

    // Stream the file content directly to the response
    file.createReadStream()
      .on('error', (err) => {
        console.error(`Error streaming file ${filePath} from bucket ${bucketName}:`, err);
        if (!res.headersSent) { // Prevent trying to send headers if an error occurs after they've been sent
          res.status(500).send('Internal Server Error: Could not stream file.');
        } else {
          // If headers were sent, just end the response to prevent hung connection
          res.end();
        }
      })
      .pipe(res);

  } catch (err) {
    console.error(`Error processing request for bucket "${bucketName}", file "${filePath}":`, err);
    // Handle specific Storage errors (e.g., bucket not found, permission denied)
    if (err.code === 403) {
      res.status(403).send('Forbidden: Insufficient permissions to access the bucket or file.');
    } else if (err.code === 404 && err.message.includes('No such bucket')) {
        res.status(404).send(`Not Found: Bucket "${bucketName}" does not exist.`);
    } else {
      res.status(500).send(`Internal Server Error: An unexpected error occurred. ${err.message}`);
    }
  }
};